#!/usr/bin/env python3
"""Revert a resharded directory (produced by compress.py) back to the
original structure, in-place.

Usage: python decompress.py <resharded_dir>
"""
import json
import os
import shutil
import sys
import tarfile

MANIFEST_NAME = "manifest.json"


def leaf_parts(index, depth, fanout):
    digits = []
    x = index
    for _ in range(depth):
        digits.append(x % fanout)
        x //= fanout
    digits.reverse()
    return digits


def chunk_relpath(index, depth, fanout, stem):
    parts = leaf_parts(index, depth, fanout)
    dirs = ["%02d" % d for d in parts[:-1]]
    fname = "%s%02d" % (stem, parts[-1])
    return os.path.join(*dirs, fname) if dirs else fname


class ConcatReader:
    """Sequential read-only stream over an ordered list of chunk files."""

    def __init__(self, paths):
        self.paths = paths
        self._i = 0
        self._f = None

    def _read_some(self, n):
        while True:
            if self._f is None:
                if self._i >= len(self.paths):
                    return b""
                self._f = open(self.paths[self._i], "rb")
                self._i += 1
            b = self._f.read(n)
            if b:
                return b
            self._f.close()
            self._f = None

    def read(self, n=-1):
        if n is None or n < 0:
            out = bytearray()
            while True:
                b = self._read_some(1 << 20)
                if not b:
                    break
                out += b
            return bytes(out)
        out = bytearray()
        while len(out) < n:
            b = self._read_some(n - len(out))
            if not b:
                break
            out += b
        return bytes(out)

    def close(self):
        if self._f is not None:
            self._f.close()
            self._f = None


def extractall(tar, path):
    try:
        tar.extractall(path=path, filter="fully_trusted")
    except TypeError:
        tar.extractall(path=path)


def main():
    if len(sys.argv) != 2:
        sys.stderr.write("Usage: python decompress.py <resharded_dir>\n")
        sys.exit(2)
    root = sys.argv[1]
    manifest_path = os.path.join(root, MANIFEST_NAME)
    with open(manifest_path) as f:
        m = json.load(f)

    fanout = m["fanout"]
    depth = m["depth"]
    count = m["count"]
    stem = m["chunk_stem"]
    data_root = os.path.join(root, m["data_dir"])

    paths = [
        os.path.join(data_root, chunk_relpath(i, depth, fanout, stem))
        for i in range(count)
    ]

    reader = ConcatReader(paths)
    try:
        with tarfile.open(mode="r|gz", fileobj=reader) as tar:
            extractall(tar, root)
    finally:
        reader.close()

    # Remove reshard artifacts, leaving only the reconstructed originals.
    if os.path.isdir(data_root):
        shutil.rmtree(data_root)
    if os.path.exists(manifest_path):
        os.remove(manifest_path)


if __name__ == "__main__":
    main()

